<?php
namespace Tests\Feature;use App\Domain\Inventory\Instances\ItemInstanceEventType;use App\Models\Character;use App\Models\CharacterItem;use App\Models\GoldTransaction;use App\Models\Item;use App\Models\ItemInstance;use App\Models\ItemInstanceEvent;use App\Models\Shop;use App\Models\ShopSale;use Illuminate\Foundation\Testing\RefreshDatabase;use Illuminate\Support\Str;use Tests\TestCase;
final class ShopSaleTest extends TestCase{use RefreshDatabase;public function test_stack_sale_is_atomic_and_replays_snapshot(){$c=Character::factory()->selected()->create();$item=$this->item(true);$row=CharacterItem::create(['character_id'=>$c->id,'item_id'=>$item->id,'quantity'=>8,'locked_quantity'=>2]);$shop=Shop::factory()->create(['buys_items'=>true,'purchase_rate_basis_points'=>5000]);$key=(string)Str::uuid();$payload=['source_type'=>'stack','character_item_id'=>$row->id,'quantity'=>3,'idempotency_key'=>$key];$this->actingAs($c->user)->postJson(route('characters.shops.sales.store',[$c,$shop]),$payload)->assertCreated()->assertJsonPath('data.total_gold',15)->assertJsonPath('data.remaining_quantity',5);$this->assertSame(5,$row->fresh()->quantity);$this->assertSame(15,(int)$c->wallet->fresh()->gold_balance);$this->postJson(route('characters.shops.sales.store',[$c,$shop]),$payload)->assertOk()->assertJsonPath('data.replayed',true)->assertJsonPath('data.total_gold',15);$this->assertSame(1,ShopSale::count());$this->assertSame(1,GoldTransaction::count());$this->assertSame(5,$row->fresh()->quantity);}
public function test_unique_sale_marks_instance_and_conflicts_do_not_repeat(){$c=Character::factory()->selected()->create();$item=$this->item(false);$instance=ItemInstance::factory()->create(['character_id'=>$c->id,'item_id'=>$item->id,'refinement_level'=>4]);$shop=Shop::factory()->create(['buys_items'=>true]);$key=(string)Str::uuid();$payload=['source_type'=>'instance','item_instance_uuid'=>$instance->uuid,'quantity'=>1,'idempotency_key'=>$key];$this->actingAs($c->user)->postJson(route('characters.shops.sales.store',[$c,$shop]),$payload)->assertCreated()->assertJsonPath('data.total_gold',10);$this->assertSame('sold',$instance->fresh()->status);$this->assertSame(1,ItemInstanceEvent::where('event_type',ItemInstanceEventType::SOLD_TO_SHOP)->count());$this->postJson(route('characters.shops.sales.store',[$c,$shop]),$payload)->assertOk()->assertJsonPath('data.replayed',true);$this->postJson(route('characters.shops.sales.store',[$c,$shop]),array_merge($payload,['quantity'=>2]))->assertStatus(422);$this->assertSame(1,ShopSale::count());}
public function test_foreign_source_shop_disabled_and_authority_fields_are_rejected(){$c=Character::factory()->selected()->create();$other=Character::factory()->create();$item=$this->item(true);$row=CharacterItem::create(['character_id'=>$other->id,'item_id'=>$item->id,'quantity'=>2,'locked_quantity'=>0]);$shop=Shop::factory()->create(['buys_items'=>false]);$base=['source_type'=>'stack','character_item_id'=>$row->id,'quantity'=>1,'idempotency_key'=>(string)Str::uuid()];$this->actingAs($c->user)->postJson(route('characters.shops.sales.store',[$c,$shop]),$base)->assertNotFound();$this->postJson(route('characters.shops.sales.store',[$c,$shop]),array_merge($base,['item_id'=>$item->id]))->assertStatus(422);$this->assertSame(0,ShopSale::count());}
private function item($stack){return Item::create(['code'=>'sale_'.Str::random(10),'name'=>'Sale item','item_type'=>$stack?'material':'equipment','equipment_type'=>$stack?null:'weapon','rarity'=>'common','is_stackable'=>$stack,'max_stack'=>$stack?99:1,'is_sellable'=>true,'sell_price'=>10,'status'=>'active']);}}
